import React, { useState, useEffect, useRef } from "react";

export default function ProfileOwner() {
  const [userData, setUserData] = useState({
    name: "Ahmed Mansouri",
    email: "ahmed@restaurant.com",
    phone: "+212 6XX XXX XXX",
    location: "Casablanca, Morocco",
    joinDate: "Janvier 2024",
    avatar: null,
    coverImage: null,
    bio: "Propriétaire passionné de restaurants, dédié à offrir la meilleure expérience culinaire."
  });

  const [myRestaurants, setMyRestaurants] = useState([
    {
      id: 1,
      name: "La Belle Table",
      cuisine: "Française",
      location: "Casablanca",
      rating: 4.8,
      image: "https://via.placeholder.com/300x200?text=Restaurant+1",
      status: "active"
    },
    {
      id: 2,
      name: "Tajina Palace",
      cuisine: "Marocaine",
      location: "Marrakech",
      rating: 4.9,
      image: "https://via.placeholder.com/300x200?text=Restaurant+2",
      status: "active"
    },
    {
      id: 3,
      name: "Sushi Master",
      cuisine: "Japonaise",
      location: "Rabat",
      rating: 4.7,
      image: "https://via.placeholder.com/300x200?text=Restaurant+3",
      status: "pending"
    }
  ]);

  const [activeTab, setActiveTab] = useState("restaurants");
  const [isEditing, setIsEditing] = useState(false);
  const [rotateX, setRotateX] = useState(0);
  const [rotateY, setRotateY] = useState(0);
  const cardRef = useRef(null);

  const handleMouseMove = (e) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    const mouseX = e.clientX - centerX;
    const mouseY = e.clientY - centerY;
    
    const maxRotate = 10;
    const rotateYValue = (mouseX / (rect.width / 2)) * maxRotate;
    const rotateXValue = (mouseY / (rect.height / 2)) * -maxRotate;
    
    setRotateY(rotateYValue);
    setRotateX(rotateXValue);
  };

  const handleMouseLeave = () => {
    setRotateX(0);
    setRotateY(0);
  };

  const handleEdit = () => {
    setIsEditing(true);
  };

  const handleSave = () => {
    setIsEditing(false);
    // Ici vous pouvez ajouter la logique pour sauvegarder dans l'API
  };

  const handleCancel = () => {
    setIsEditing(false);
  };

  const handleAddRestaurant = () => {
    // Logique pour ajouter un nouveau restaurant
    alert("Formulaire d'ajout de restaurant à implémenter");
  };

  const handleEditRestaurant = (id) => {
    alert(`Modifier le restaurant avec ID: ${id}`);
  };

  const handleDeleteRestaurant = (id) => {
    if (window.confirm("Êtes-vous sûr de vouloir supprimer ce restaurant ?")) {
      setMyRestaurants(myRestaurants.filter(r => r.id !== id));
    }
  };

  return (
    <div className="owner-profile-container">
      <div className="bg-gradient"></div>
      <div className="noise-overlay"></div>
      
      <div className="profile-wrapper">
        <div
          ref={cardRef}
          className="profile-card"
          onMouseMove={handleMouseMove}
          onMouseLeave={handleMouseLeave}
          style={{
            transform: `perspective(1500px) rotateX(${rotateX}deg) rotateY(${rotateY}deg)`,
            transition: "transform 0.1s ease-out"
          }}
        >
          <div className="card-glow"></div>
          
          {/* Cover Image */}
          <div className="cover-section">
            <div className="cover-image">
              <img 
                src={userData.coverImage || "https://via.placeholder.com/1200x300?text=Cover"} 
                alt="Cover"
              />
              <button className="edit-cover-btn">📷</button>
            </div>
            
            {/* Avatar */}
            <div className="avatar-section">
              <div className="avatar">
                <img 
                  src={userData.avatar || "https://via.placeholder.com/120x120?text=Owner"} 
                  alt="Avatar"
                />
                <button className="edit-avatar-btn">✏️</button>
              </div>
            </div>
          </div>

          {/* Profile Info */}
          <div className="profile-info">
            {!isEditing ? (
              <>
                <h1 className="owner-name">{userData.name}</h1>
                <p className="owner-title">🏪 Propriétaire de Restaurant</p>
                <div className="info-row">
                  <span>📧 {userData.email}</span>
                  <span>📞 {userData.phone}</span>
                  <span>📍 {userData.location}</span>
                </div>
                <p className="owner-bio">{userData.bio}</p>
                <p className="join-date">📅 Membre depuis: {userData.joinDate}</p>
                <button className="edit-btn" onClick={handleEdit}>
                  ✏️ Modifier le profil
                </button>
              </>
            ) : (
              <div className="edit-form">
                <h2>Modifier le profil</h2>
                <input 
                  type="text" 
                  defaultValue={userData.name}
                  placeholder="Nom complet"
                  onChange={(e) => setUserData({...userData, name: e.target.value})}
                />
                <input 
                  type="email" 
                  defaultValue={userData.email}
                  placeholder="Email"
                  onChange={(e) => setUserData({...userData, email: e.target.value})}
                />
                <input 
                  type="tel" 
                  defaultValue={userData.phone}
                  placeholder="Téléphone"
                  onChange={(e) => setUserData({...userData, phone: e.target.value})}
                />
                <input 
                  type="text" 
                  defaultValue={userData.location}
                  placeholder="Localisation"
                  onChange={(e) => setUserData({...userData, location: e.target.value})}
                />
                <textarea 
                  defaultValue={userData.bio}
                  placeholder="Bio"
                  rows="3"
                  onChange={(e) => setUserData({...userData, bio: e.target.value})}
                />
                <div className="edit-buttons">
                  <button className="save-btn" onClick={handleSave}>💾 Sauvegarder</button>
                  <button className="cancel-btn" onClick={handleCancel}>❌ Annuler</button>
                </div>
              </div>
            )}
          </div>

          {/* Tabs */}
          <div className="tabs-section">
            <button 
              className={`tab-btn ${activeTab === "restaurants" ? "active" : ""}`}
              onClick={() => setActiveTab("restaurants")}
            >
              🍽️ Mes Restaurants ({myRestaurants.length})
            </button>
            <button 
              className={`tab-btn ${activeTab === "stats" ? "active" : ""}`}
              onClick={() => setActiveTab("stats")}
            >
              📊 Statistiques
            </button>
            <button 
              className={`tab-btn ${activeTab === "settings" ? "active" : ""}`}
              onClick={() => setActiveTab("settings")}
            >
              ⚙️ Paramètres
            </button>
          </div>

          {/* Content */}
          <div className="tab-content">
            {activeTab === "restaurants" && (
              <div>
                <div className="restaurants-header">
                  <h3>Mes Restaurants</h3>
                  <button className="add-restaurant-btn" onClick={handleAddRestaurant}>
                    + Ajouter un restaurant
                  </button>
                </div>
                
                <div className="restaurants-grid">
                  {myRestaurants.map((restaurant) => (
                    <div key={restaurant.id} className="restaurant-card">
                      <div className="restaurant-image">
                        <img src={restaurant.image} alt={restaurant.name} />
                        <span className={`status-badge ${restaurant.status}`}>
                          {restaurant.status === "active" ? "✅ Actif" : "⏳ En attente"}
                        </span>
                      </div>
                      <div className="restaurant-info">
                        <h4>{restaurant.name}</h4>
                        <p className="cuisine">🍳 {restaurant.cuisine}</p>
                        <p className="location">📍 {restaurant.location}</p>
                        <div className="rating">
                          ⭐ {restaurant.rating} / 5
                        </div>
                        <div className="restaurant-actions">
                          <button 
                            className="action-btn edit"
                            onClick={() => handleEditRestaurant(restaurant.id)}
                          >
                            ✏️ Modifier
                          </button>
                          <button 
                            className="action-btn delete"
                            onClick={() => handleDeleteRestaurant(restaurant.id)}
                          >
                            🗑️ Supprimer
                          </button>
                          <button className="action-btn view">
                            👁️ Voir
                          </button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                {myRestaurants.length === 0 && (
                  <div className="no-restaurants">
                    <p>Vous n'avez pas encore de restaurants.</p>
                    <button onClick={handleAddRestaurant}>➕ Ajouter mon premier restaurant</button>
                  </div>
                )}
              </div>
            )}

            {activeTab === "stats" && (
              <div className="stats-section">
                <div className="stats-grid">
                  <div className="stat-card">
                    <h3>📊 Nombre total de restaurants</h3>
                    <p className="stat-number">{myRestaurants.length}</p>
                  </div>
                  <div className="stat-card">
                    <h3>⭐ Note moyenne</h3>
                    <p className="stat-number">
                      {(myRestaurants.reduce((acc, r) => acc + r.rating, 0) / myRestaurants.length || 0).toFixed(1)}
                    </p>
                  </div>
                  <div className="stat-card">
                    <h3>🏆 Restaurants actifs</h3>
                    <p className="stat-number">
                      {myRestaurants.filter(r => r.status === "active").length}
                    </p>
                  </div>
                  <div className="stat-card">
                    <h3>📈 Total des ventes</h3>
                    <p className="stat-number">0 DH</p>
                  </div>
                </div>
              </div>
            )}

            {activeTab === "settings" && (
              <div className="settings-section">
                <div className="setting-group">
                  <h3>🔔 Notifications</h3>
                  <label>
                    <input type="checkbox" /> Recevoir les alertes de réservations
                  </label>
                  <label>
                    <input type="checkbox" /> Recevoir les avis clients
                  </label>
                  <label>
                    <input type="checkbox" /> Newsletter
                  </label>
                </div>
                <div className="setting-group">
                  <h3>🔒 Sécurité</h3>
                  <button className="security-btn">Changer le mot de passe</button>
                  <button className="security-btn danger">Désactiver le compte</button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      <style jsx>{`
        * {
